package main

import "fmt"

type Player struct {
    Name    string
    Health  int
    MaxHealth int
    Attack  int
    Defense int
    Level   int
    Experience int
}

// ---- Method with value receiver (read-only) ----
func (p Player) Display() {
    fmt.Printf("=== %s ===\n", p.Name)
    fmt.Printf("Level: %d\n", p.Level)
    fmt.Printf("Health: %d/%d\n", p.Health, p.MaxHealth)
    fmt.Printf("Attack: %d\n", p.Attack)
    fmt.Printf("Defense: %d\n", p.Defense)
    fmt.Printf("Experience: %d/%d\n", p.Experience, p.Level*100)
}

// ---- Method with pointer receiver (modifies struct) ----
func (p *Player) TakeDamage(damage int) {
    actualDamage := damage - p.Defense/2
    if actualDamage > 0 {
        p.Health -= actualDamage
        if p.Health < 0 {
            p.Health = 0
        }
        fmt.Printf("%s took %d damage! Health: %d\n", p.Name, actualDamage, p.Health)
    } else {
        fmt.Printf("%s blocked the attack!\n", p.Name)
    }
}

func (p *Player) Heal(amount int) {
    p.Health += amount
    if p.Health > p.MaxHealth {
        p.Health = p.MaxHealth
    }
    fmt.Printf("%s healed! Health: %d\n", p.Name, p.Health)
}

func (p *Player) GainExperience(amount int) {
    p.Experience += amount
    fmt.Printf("%s gained %d XP!\n", p.Name, amount)

    for p.Experience >= p.Level*100 {
        p.LevelUp()
    }
}

func (p *Player) LevelUp() {
    p.Level++
    p.MaxHealth += 20
    p.Health = p.MaxHealth
    p.Attack += 5
    p.Defense += 3
    p.Experience -= (p.Level-1)*100
    fmt.Printf("🎉 %s reached level %d!\n", p.Name, p.Level)
}

func (p Player) IsAlive() bool {
    return p.Health > 0
}

func main() {
    // ---- Creating a player ----
    hero := Player{
        Name:    "Aragorn",
        Health:  100,
        MaxHealth: 100,
        Attack:  20,
        Defense: 10,
        Level:   1,
        Experience: 0,
    }

    hero.Display()

    // ---- Using methods ----
    hero.TakeDamage(30)
    hero.Heal(20)
    hero.GainExperience(50)
    hero.GainExperience(70)

    fmt.Println("\nAfter actions:")
    hero.Display()

    fmt.Printf("\nIs alive? %t\n", hero.IsAlive())

    // ---- Pointer receiver vs value receiver ----
    // Value receiver: works on a copy
    // Pointer receiver: works on the original

    // ---- Method expression ----
    // You can call methods as functions
    p := &hero
    (*p).TakeDamage(10)
    p.TakeDamage(10)  // Auto-dereference
}

