package main

import "fmt"

type Item struct {
    Name   string
    Value  int
    Weight int
}

func (i Item) Display() {
    fmt.Println("Item:", i)
}

func (i *Item) SetValue(v int) {
    i.Value = v
}

func main() {
    item := Item{Name: "Sword", Value: 50, Weight: 3}
    item.Display()

    item.SetValue(100)
    item.Display()
}
